function InputDock({ value, onChange, onSubmit, placeholder, disabled, drawerWidth = 0 }) {
  const [focused, setFocused] = useState(false);
  const [sendHover, setSendHover] = useState(false);
  const [dockVisible, setDockVisible] = useState(false);
  const textareaRef = useRef(null);
  const hideTimerRef = useRef(null);
  const lastScrollRef = useRef(0);

  // Show dock on scroll, hide 3s after scrolling stops
  useEffect(() => {
    const handler = () => {
      setDockVisible(true);
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
      hideTimerRef.current = setTimeout(() => setDockVisible(false), 3500);
    };
    window.addEventListener("scroll", handler, { passive: true });
    document.addEventListener("scroll", handler, { passive: true, capture: true });
    // Also show on mouse move near the bottom 80px of the viewport
    const mouseHandler = (e) => {
      if (e.clientY > window.innerHeight - 80) {
        setDockVisible(true);
        if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
        hideTimerRef.current = setTimeout(() => setDockVisible(false), 3500);
      }
    };
    window.addEventListener("mousemove", mouseHandler, { passive: true });
    // Brief flash on mount
    setTimeout(() => { setDockVisible(true); hideTimerRef.current = setTimeout(() => setDockVisible(false), 3000); }, 500);
    return () => {
      window.removeEventListener("scroll", handler);
      document.removeEventListener("scroll", handler, { capture: true });
      window.removeEventListener("mousemove", mouseHandler);
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    };
  }, []);

  // Keep visible while focused or has content
  useEffect(() => {
    if (focused || (value && value.trim())) {
      setDockVisible(true);
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    }
  }, [focused, value]);

  const autoResize = () => {
    const ta = textareaRef.current;
    if (ta) {
      ta.style.height = "auto";
      const scrollH = ta.scrollHeight;
      ta.style.height = Math.min(scrollH, 150) + "px";
      ta.style.overflowY = scrollH > 150 ? "auto" : "hidden";
    }
  };

  const handleSubmit = () => {
    console.log("[InputDock] submit fired, value:", JSON.stringify(value));
    if (value.trim() && !disabled) {
      onSubmit();
      // Reset textarea height after clearing
      setTimeout(() => {
        const ta = textareaRef.current;
        if (ta) { ta.style.height = "auto"; ta.style.overflowY = "hidden"; }
      }, 0);
    }
  };

  return (
    <div
      style={{
        position: "fixed",
        bottom: 0,
        left: 72,
        right: drawerWidth,
        padding: "16px 32px 24px",
        background: "linear-gradient(0deg, #f5f0e8 0%, #f5f0e880 50%, transparent 100%)",
        zIndex: 50,
        transition: "right 0.3s ease, transform 0.4s ease, opacity 0.4s ease",
        transform: dockVisible ? "translateY(0)" : "translateY(100%)",
        opacity: dockVisible ? 1 : 0,
        pointerEvents: dockVisible ? "auto" : "none",
      }}
    >
      <div style={{ maxWidth: 740, margin: "0 auto", display: "flex", gap: 10, alignItems: "center" }}>
        <textarea
          ref={textareaRef}
          id="inputDockOmni"
          value={value}
          onChange={(e) => { onChange(e); setTimeout(autoResize, 0); }}
          onFocus={() => setFocused(true)}
          onBlur={() => setFocused(false)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              handleSubmit();
            }
          }}
          placeholder={placeholder || "Ask a follow-up or explore something new..."}
          disabled={disabled}
          rows={1}
          style={{
            flex: 1,
            padding: "14px 18px",
            border: `2px solid ${focused ? T.gold : "#1a2744"}`,
            borderRadius: 18,
            fontSize: 14,
            fontFamily: "inherit",
            color: "#1a2744",
            background: "#fff",
            outline: "none",
            transition: "border-color 0.2s",
            resize: "none",
            overflow: "hidden",
            lineHeight: 1.5,
            minHeight: 48,
            maxHeight: 150,
          }}
        />
        <button
          onClick={handleSubmit}
          onMouseEnter={() => setSendHover(true)}
          onMouseLeave={() => setSendHover(false)}
          style={{
            width: 38,
            height: 38,
            background: sendHover ? "#2a3a5a" : "#1a2744",
            border: "none",
            borderRadius: 10,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            transition: "all 0.15s",
            flexShrink: 0,
            transform: sendHover ? "scale(1.05)" : undefined,
          }}
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#ffce3a" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 6 15 12 9 18" /></svg>
        </button>
      </div>
    </div>
  );
}

