function VideoModal({ title: rawTitle, subtitle: rawSubtitle, videoId, timecodeUrl, podcastUrl, onClose }) {
  const title = decodeHTML(rawTitle);
  const subtitle = decodeHTML(rawSubtitle);
  if (!title) return null;

  // Audio mode: S3 podcast
  if (podcastUrl) {
    return (
      <div
        style={{
          position: "fixed", inset: 0, zIndex: 100,
          background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)",
          display: "flex", alignItems: "center", justifyContent: "center",
        }}
        onClick={onClose}
      >
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            width: 480, background: T.queryBg, borderRadius: 14,
            overflow: "hidden", boxShadow: "0 20px 60px rgba(0,0,0,0.5)",
          }}
        >
          {/* Header */}
          <div style={{
            display: "flex", alignItems: "center", justifyContent: "space-between",
            padding: "14px 18px",
          }}>
            <span style={{ fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", fontSize: 15, fontWeight: 700, color: "#fff", flex: 1, marginRight: 12 }}>
              {title}{subtitle ? ` — ${subtitle}` : ""}
            </span>
            <button
              onClick={onClose}
              style={{
                background: "none", border: "none", color: "rgba(255,255,255,0.5)",
                cursor: "pointer", fontSize: 20, lineHeight: 1, flexShrink: 0,
              }}
            >
              ×
            </button>
          </div>
          {/* Waveform visualization */}
          <div style={{
            display: "flex", alignItems: "center", justifyContent: "center",
            gap: 4, padding: "16px 24px 8px", height: 48,
          }}>
            {[10, 18, 14, 26, 20, 30, 16, 28, 12, 24, 18, 22, 14, 20, 10].map((h, i) => (
              <div key={i} style={{ width: 4, height: h, borderRadius: 2, background: `rgba(245,184,0,${0.4 + i * 0.04})` }} />
            ))}
          </div>
          {/* Audio player */}
          <div style={{ padding: "12px 24px 24px" }}>
            <audio controls autoPlay src={podcastUrl}
                   style={{ width: "100%", borderRadius: 8, filter: "invert(1) hue-rotate(180deg)" }} />
          </div>
          {/* Footer */}
          <div style={{
            padding: "0 18px 14px",
            fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", fontSize: 12, color: "rgba(255,255,255,0.45)",
          }}>
            via UnitedTribes Media Archive
          </div>
        </div>
      </div>
    );
  }

  // Build embed URL: use timecode start time if available
  let embedUrl = null;
  if (videoId) {
    let startParam = "";
    if (timecodeUrl) {
      const tMatch = timecodeUrl.match(/[?&]t=(\d+)/);
      if (tMatch) startParam = `&start=${tMatch[1]}`;
    }
    embedUrl = `https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1&autoplay=0${startParam}`;
  }
  return (
    <div
      style={{
        position: "fixed", inset: 0, zIndex: 100,
        background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)",
        display: "flex", alignItems: "center", justifyContent: "center",
      }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          width: 640, background: T.queryBg, borderRadius: 14,
          overflow: "hidden", boxShadow: "0 20px 60px rgba(0,0,0,0.5)",
        }}
      >
        {/* Header */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "14px 18px",
        }}>
          <span style={{ fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", fontSize: 15, fontWeight: 700, color: "#fff", flex: 1, marginRight: 12 }}>
            {title}{subtitle ? ` — ${subtitle}` : ""}
          </span>
          <button
            onClick={onClose}
            style={{
              background: "none", border: "none", color: "rgba(255,255,255,0.5)",
              cursor: "pointer", fontSize: 20, lineHeight: 1, flexShrink: 0,
            }}
          >
            ×
          </button>
        </div>

        {/* Video area */}
        {embedUrl ? (
          <div style={{ width: "100%", aspectRatio: "16/9", background: "#000" }}>
            <iframe
              src={embedUrl}
              width="100%"
              height="100%"
              frameBorder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
              title={title}
              style={{ border: "none" }}
            />
          </div>
        ) : (
          <div
            style={{
              width: "100%", aspectRatio: "16/9", background: "#000",
              display: "flex", alignItems: "center", justifyContent: "center",
              cursor: "pointer",
            }}
          >
            <div
              style={{
                width: 64, height: 64, borderRadius: "50%",
                background: "rgba(255,255,255,0.15)", backdropFilter: "blur(8px)",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 24, color: "#fff",
                border: "2px solid rgba(255,255,255,0.2)",
              }}
            >
              ▶
            </div>
          </div>
        )}

        {/* Footer */}
        <div style={{
          padding: "12px 18px",
          fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", fontSize: 12, color: "rgba(255,255,255,0.45)",
        }}>
          {videoId ? "via YouTube · Powered by UnitedTribes Knowledge Graph" : "Video not available · Placeholder"}
        </div>
      </div>
    </div>
  );
}

