      if (tab.id === "music") { counts[tab.id] = jdAlbumCount > 0 ? jdAlbumCount : jdScoreTracks.length + jdMusicCards.length; return; }
      if (tab.id === "theme") { counts[tab.id] = jdThemeCards.length; return; }
